function formatTime(t,o){var r=Math.floor(t%1*(o||0)),a=Math.floor(t),e=Math.floor(a/60),o=Math.floor(e/60),t=t=>t<10?t<=0?"00":`0${t.toString()}`:t.toString();return e%=60,a%=60,`${0<o?`${t(o)}:`:""}${t(e)}:${t(a)}${r?`:${t(r)}`:""}`}function timeToSeconds(t){t=t.replace(/;/g,":").split(":");let o=0;return 3===t.length?(o+=60*parseFloat(t[0])*60,o+=60*parseFloat(t[1]),o+=parseFloat(t[2])):(o+=60*parseFloat(t[0]),o+=parseFloat(t[1])),o}export{formatTime,timeToSeconds};